import{_ as a,o as e,c as n,a2 as o}from"./chunks/framework.ChW7XBuO.js";const u=JSON.parse('{"title":"会话工具","description":"10 工具会话管理套件 — 会话列表/读取/搜索/分析/导出/标签/续期/时间线与链接工具","frontmatter":{"title":"会话工具","description":"10 工具会话管理套件 — 会话列表/读取/搜索/分析/导出/标签/续期/时间线与链接工具"},"headers":[],"relativePath":"04-Advanced/session-tools.md","filePath":"04-Advanced/session-tools.md"}'),t={name:"04-Advanced/session-tools.md"};function i(p,s,l,d,c,r){return e(),n("div",null,[...s[0]||(s[0]=[o(`<h1 id="会话工具" tabindex="-1">会话工具 <a class="header-anchor" href="#会话工具" aria-label="Permalink to &quot;会话工具&quot;">​</a></h1><blockquote><p><strong>v0.17.0 引入</strong> — 10 工具会话管理套件（4 个兼容 omo + 6 个独有），覆盖列表/读取/搜索/分析/导出/标签/续期/时间线/链接（CHANGELOG.md:198）</p></blockquote><blockquote><p><strong>相关文档：</strong> <a href="/rolebox-docs/04-Advanced/memory-system.html">记忆系统</a> — 跨会话持久记忆 | <a href="/rolebox-docs/03-Reference/cli.html">CLI 参考</a> — 命令行管理 | <a href="/rolebox-docs/03-Reference/dispatch-config.html">调度配置</a> — 并发与预算</p></blockquote><p>rolebox 提供了一套完整的会话管理工具套件，共 10 个工具，让代理能够列出、读取、搜索、分析、导出、标记和管理会话。其中 4 个工具与 oh-my-openagent (omo) 兼容，6 个工具为 rolebox 独有。</p><div class="tip custom-block"><p class="custom-block-title">omo 兼容说明</p><p>4 个工具（<code>session_list</code>、<code>session_read</code>、<code>session_search</code>、<code>session_info</code>）与 oh-my-openagent 同名且接口兼容，但功能更强。如果同时使用 omo 和 rolebox，rolebox 的版本会自动覆盖 omo 的工具——这是一个安全的覆盖，因为 rolebox 版本向后兼容 omo 的输入格式。其余 6 个工具为 rolebox 独有，不会产生冲突。</p></div><h2 id="工具总览" tabindex="-1">工具总览 <a class="header-anchor" href="#工具总览" aria-label="Permalink to &quot;工具总览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具</th><th>类型</th><th>功能描述</th></tr></thead><tbody><tr><td><code>session_list</code></td><td>兼容增强</td><td>列出所有会话，支持按日期范围、项目路径、代理名称筛选。显示 token 消耗、成本、模型信息</td></tr><tr><td><code>session_read</code></td><td>兼容增强</td><td>读取会话完整记录，支持消息类型筛选、分页、工具调用展开</td></tr><tr><td><code>session_search</code></td><td>兼容增强</td><td>跨会话全文搜索，支持上下文窗口显示匹配位置</td></tr><tr><td><code>session_info</code></td><td>兼容增强</td><td>查看会话详细元数据：token 分解、成本、工具频率、模型分布</td></tr><tr><td><code>session_analytics</code></td><td>🆕 独有</td><td>分析仪表盘 — token 趋势、工具调用分布、按日/周/模型/代理分组统计</td></tr><tr><td><code>session_export</code></td><td>🆕 独有</td><td>将会话导出为 Markdown 或 JSON 文件，支持离线查看与分享</td></tr><tr><td><code>session_tag</code></td><td>🆕 独有</td><td>为会话添加/移除标签，便于分类和检索</td></tr><tr><td><code>session_resume</code></td><td>🆕 独有</td><td>从已有会话恢复上下文，创建延续会话</td></tr><tr><td><code>session_timeline</code></td><td>🆕 独有</td><td>按时间线汇总会话活动，可视化工作模式</td></tr><tr><td><code>session_link</code></td><td>🆕 独有</td><td>关联调度任务与会话，桥接 dispatch 和 session 两个系统域</td></tr></tbody></table><h2 id="最常用工具使用示例" tabindex="-1">最常用工具使用示例 <a class="header-anchor" href="#最常用工具使用示例" aria-label="Permalink to &quot;最常用工具使用示例&quot;">​</a></h2><h3 id="session-list-—-列出会话" tabindex="-1"><code>session_list</code> — 列出会话 <a class="header-anchor" href="#session-list-—-列出会话" aria-label="Permalink to &quot;\`session_list\` — 列出会话&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>session_list(limit=10, from_date=&quot;2026-07-01&quot;)</span></span></code></pre></div><p>返回表格：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>| Session ID | Title | Agent | Model | Msgs | Created | Updated | Tokens In | Tokens Out | Cost |</span></span></code></pre></div><p>可选 <code>include_archived: true</code> 包含已归档会话，<code>include_message_count: true</code> 获取消息数量。</p><h3 id="session-read-—-读取会话" tabindex="-1"><code>session_read</code> — 读取会话 <a class="header-anchor" href="#session-read-—-读取会话" aria-label="Permalink to &quot;\`session_read\` — 读取会话&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>session_read(session_id=&quot;abc123&quot;, message_type=&quot;assistant&quot;, limit=50)</span></span></code></pre></div><p>支持四种消息类型筛选：<code>user</code>、<code>assistant</code>、<code>tool</code>、<code>all</code>。工具调用结果会自动展开（截断至 2000 字符）。</p><h3 id="session-search-—-搜索会话" tabindex="-1"><code>session_search</code> — 搜索会话 <a class="header-anchor" href="#session-search-—-搜索会话" aria-label="Permalink to &quot;\`session_search\` — 搜索会话&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>session_search(query=&quot;数据库迁移策略&quot;, case_sensitive=false)</span></span></code></pre></div><p>跨会话全文搜索，返回匹配行及上下文（±2 条消息）。</p><h3 id="session-info-—-会话详情" tabindex="-1"><code>session_info</code> — 会话详情 <a class="header-anchor" href="#session-info-—-会话详情" aria-label="Permalink to &quot;\`session_info\` — 会话详情&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>session_info(session_id=&quot;abc123&quot;, include_todos=true)</span></span></code></pre></div><p>返回完整元数据：token 消耗分解、成本计算、文件变更列表、子会话表格、待办事项完成统计。</p><h3 id="session-export-—-导出会话" tabindex="-1"><code>session_export</code> — 导出会话 <a class="header-anchor" href="#session-export-—-导出会话" aria-label="Permalink to &quot;\`session_export\` — 导出会话&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>session_export(session_id=&quot;abc123&quot;, format=&quot;markdown&quot;, output_path=&quot;exports/session.md&quot;)</span></span></code></pre></div><p>支持 <code>markdown</code> 和 <code>json</code> 两种格式。提供 <code>output_path</code> 时写入文件（原子写入：先写 <code>.tmp</code> 再 <code>rename</code>），不提供时返回内联字符串。</p><h3 id="session-resume-—-恢复会话" tabindex="-1"><code>session_resume</code> — 恢复会话 <a class="header-anchor" href="#session-resume-—-恢复会话" aria-label="Permalink to &quot;\`session_resume\` — 恢复会话&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>session_resume(session_id=&quot;abc123&quot;, agent=&quot;code-reviewer&quot;)</span></span></code></pre></div><p>从源会话提取最后 3 条助手消息作为上下文，创建延续会话并返回新的会话 ID。</p><h3 id="session-link-—-关联任务与会话" tabindex="-1"><code>session_link</code> — 关联任务与会话 <a class="header-anchor" href="#session-link-—-关联任务与会话" aria-label="Permalink to &quot;\`session_link\` — 关联任务与会话&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>session_link(task_id=&quot;task-001&quot;, session_id=&quot;abc123&quot;)</span></span></code></pre></div><p>持久化存储在 <code>.rolebox/state/session-links.json</code>。支持三种操作模式：添加链接、查询链接、列出全部链接。</p><h2 id="标签系统" tabindex="-1">标签系统 <a class="header-anchor" href="#标签系统" aria-label="Permalink to &quot;标签系统&quot;">​</a></h2><p><code>session_tag</code> 工具使用 opencode 内建的会话 <code>metadata</code> 字段（键 <code>rolebox_tags</code>），无需额外持久化文件：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>session_tag(session_id=&quot;abc123&quot;, tags=[&quot;重要&quot;, &quot;待复习&quot;])    # 添加标签</span></span>
<span class="line"><span>session_tag(session_id=&quot;abc123&quot;, list=true)                  # 查看标签</span></span>
<span class="line"><span>session_tag(session_id=&quot;abc123&quot;, remove=[&quot;待复习&quot;])          # 移除标签</span></span></code></pre></div><h2 id="分析仪表盘" tabindex="-1">分析仪表盘 <a class="header-anchor" href="#分析仪表盘" aria-label="Permalink to &quot;分析仪表盘&quot;">​</a></h2><p>虽然 <code>session_analytics</code> 作为独立工具正在规划中，但当前可通过 <code>session_info</code>（别名 <code>session_inspect</code>）获取完整的分析仪表盘输出。该工具提供与 <code>session_analytics</code> 相同的 <code>collectSessionAnalytics</code> 数据源。</p><p>输出示例：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>### Token Usage</span></span>
<span class="line"><span>  Input:     45,231</span></span>
<span class="line"><span>  Output:    12,847</span></span>
<span class="line"><span>  Reasoning: 3,210</span></span>
<span class="line"><span>  Cache read:   8,400</span></span>
<span class="line"><span>  Cache write:  2,100</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Total Cost: $0.002345</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### Models Used</span></span>
<span class="line"><span>  openai/gpt-4o: 12 messages</span></span>
<span class="line"><span>  openai/gpt-4o-mini: 3 messages</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### Tool Usage</span></span>
<span class="line"><span>  session_list: 8 calls</span></span>
<span class="line"><span>  memory_write: 5 calls</span></span>
<span class="line"><span>  bash: 12 calls</span></span>
<span class="line"><span>  dispatch: 3 calls</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### File Changes</span></span>
<span class="line"><span>  Files modified: 4</span></span>
<span class="line"><span>  Additions: 120</span></span>
<span class="line"><span>  Deletions: 45</span></span></code></pre></div><p><code>session_info</code> 的 <code>include_todos=true</code> 参数还会生成待办事项完成统计，帮助评估会话进度。</p><div class="tip custom-block"><p class="custom-block-title">使用场景</p><p>在长时间会话结束时查看 <code>session_info</code>，评估 token 消耗是否合理、哪些工具被高频调用、文件变更范围是否符合预期。</p></div><h2 id="调度时间线" tabindex="-1">调度时间线 <a class="header-anchor" href="#调度时间线" aria-label="Permalink to &quot;调度时间线&quot;">​</a></h2><p>按时间维度汇总调度任务活动的工具是 <code>task_chronology</code>（位于 dispatch 域，非 session 域）。<code>session_timeline</code> 工具正在规划中，当前推荐使用 <code>task_chronology</code>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>task_chronology(from_date=&quot;2026-07-01&quot;, to_date=&quot;2026-07-20&quot;, group_by=&quot;day&quot;)</span></span></code></pre></div><p>输出示例：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Task Chronology</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Grouped by: day</span></span>
<span class="line"><span>Range: 2026-07-01 to 2026-07-20</span></span>
<span class="line"><span></span></span>
<span class="line"><span>| Bucket | Count | Pending | Running | Completed | Awaiting_approval | Error | Cancelled | Timeout |</span></span>
<span class="line"><span>|--------|-------|---------|---------|-----------|-------------------|-------|-----------|---------|</span></span>
<span class="line"><span>| 2026-07-15 | 5 | 0 | 0 | 4 | 1 | 0 | 0 | 0 |</span></span>
<span class="line"><span>| 2026-07-16 | 12 | 0 | 0 | 10 | 2 | 0 | 0 | 0 |</span></span>
<span class="line"><span>| 2026-07-17 | 8 | 0 | 1 | 6 | 0 | 1 | 0 | 0 |</span></span></code></pre></div><p>支持三种分组方式：<code>hour</code>（按小时）、<code>day</code>（按天）、<code>agent</code>（按代理名称）。可用于分析工作节奏、检测异常堆积或评估不同代理的负载分布。</p><div class="tip custom-block"><p class="custom-block-title">为什么 task_chronology 在 dispatch 域而非 session 域？</p><p>会话活动（消息、token）属于 session 域；调度任务的生命周期（触发、完成、错误）属于 dispatch 域。<code>task_chronology</code> 追踪的是 dispatch 任务的时间线，而非消息时间线。</p></div><h2 id="会话分析-recipes" tabindex="-1">会话分析 Recipes <a class="header-anchor" href="#会话分析-recipes" aria-label="Permalink to &quot;会话分析 Recipes&quot;">​</a></h2><p>以下是一组常用会话分析模式，帮助你在实际工作流中高效利用会话工具套件。</p><h3 id="按日期查找会话" tabindex="-1">按日期查找会话 <a class="header-anchor" href="#按日期查找会话" aria-label="Permalink to &quot;按日期查找会话&quot;">​</a></h3><p>当需要回顾某一天或某一周的工作时，使用 <code>session_list</code> 的日期过滤参数：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>session_list(from_date=&quot;2026-07-01&quot;, to_date=&quot;2026-07-10&quot;, limit=50)</span></span></code></pre></div><p>返回该日期范围内的所有会话。结合 <code>session_info</code> 可以快速了解当天的工作量：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>session_info(session_id=&quot;abc123&quot;)</span></span></code></pre></div><p>也可以跨项目搜索：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>session_list(from_date=&quot;2026-07-01&quot;, project_path=&quot;/path/to/other-project&quot;)</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">日期范围技巧</p><ul><li>查今天：<code>from_date=&quot;$(date +%F)&quot;</code></li><li>查本周一至今：<code>from_date=&quot;2026-07-13&quot;</code>（手动填入周一日期）</li><li>指定精确时间：ISO 8601 格式如 <code>2026-07-15T09:00:00</code> 同样支持</li></ul></div><h3 id="对比两个会话" tabindex="-1">对比两个会话 <a class="header-anchor" href="#对比两个会话" aria-label="Permalink to &quot;对比两个会话&quot;">​</a></h3><p>当你需要比较两次不同实现尝试的结果时，使用 <code>session_diff</code> 工具对比会话之间的差异：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>session_diff(session_id=&quot;abc123&quot;, other_session_id=&quot;def456&quot;)</span></span></code></pre></div><p>输出会显示两次会话在文件变更、token 消耗、工具调用分布等方面的对比：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Session Diff: abc123 vs def456</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### File Changes</span></span>
<span class="line"><span>  abc123: 4 files modified (+120 / -45)</span></span>
<span class="line"><span>  def456: 7 files modified (+230 / -89)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### Token Usage</span></span>
<span class="line"><span>  abc123: Input 45,231 | Output 12,847</span></span>
<span class="line"><span>  def456: Input 78,902 | Output 23,456</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### Tool Call Distribution</span></span>
<span class="line"><span>  abc123: bash(12) memory_write(5) dispatch(3)</span></span>
<span class="line"><span>  def456: bash(20) memory_write(8) session_search(4)</span></span></code></pre></div><p>这在评估不同方案的工作量和效果时非常有用。若需查看具体消息内容的差异，可以配合 <code>session_read</code> 分别读取两个会话的完整记录手动比较。</p><h3 id="fork-会话用于探索" tabindex="-1">Fork 会话用于探索 <a class="header-anchor" href="#fork-会话用于探索" aria-label="Permalink to &quot;Fork 会话用于探索&quot;">​</a></h3><p>当你有以下需求时，使用 <code>session_fork</code> 将会话分叉：</p><ul><li>想在一个已完成会话的基础上尝试不同方向</li><li>需要保留原有会话的完整性作为基准线</li><li>对比两种不同策略的结果</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>session_fork(session_id=&quot;abc123&quot;)</span></span></code></pre></div><p>分叉会创建一个新会话，继承原会话的历史消息（最后 N 条助手消息）作为上下文起点。新会话拥有独立的 ID，与原会话互不影响：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Forked session created.</span></span>
<span class="line"><span>  Source: abc123</span></span>
<span class="line"><span>  Forked: xyz789</span></span></code></pre></div><p>之后可以在分叉会话中自由探索，而不影响原始会话的完整性。</p><h3 id="完整的工作流示例" tabindex="-1">完整的工作流示例 <a class="header-anchor" href="#完整的工作流示例" aria-label="Permalink to &quot;完整的工作流示例&quot;">​</a></h3><p>一个典型的问题诊断工作流：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 1. 按日期定位相关会话</span></span>
<span class="line"><span>session_list(from_date=&quot;2026-07-13&quot;, to_date=&quot;2026-07-15&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 2. 深入读取关键会话的详情</span></span>
<span class="line"><span>session_info(session_id=&quot;abc123&quot;, include_todos=true)</span></span>
<span class="line"><span>session_read(session_id=&quot;abc123&quot;, include_tool_results=true)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 3. 搜索相关关键词确认问题范围</span></span>
<span class="line"><span>session_search(query=&quot;数据库连接超时&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 4. Fork 一个隔离的调试会话</span></span>
<span class="line"><span>session_fork(session_id=&quot;abc123&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 5. 在分叉会话中尝试修复，完成后导出</span></span>
<span class="line"><span>session_export(session_id=&quot;xyz789&quot;, format=&quot;markdown&quot;, output_path=&quot;exports/debug-session.md&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 6. 与原始会话对比验证差异</span></span>
<span class="line"><span>session_diff(session_id=&quot;abc123&quot;, other_session_id=&quot;xyz789&quot;)</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">使用 <code>session_resume</code> 还是 <code>session_fork</code>？</p><ul><li>需要<strong>延续</strong>未完成的工作 → 使用 <code>session_resume</code>（创建子会话）</li><li>想要<strong>复制上下文</strong>用于探索性工作 → 使用 <code>session_fork</code>（创建独立副本）</li><li><code>session_resume</code> 保持父子关系（新会话以旧会话为父），<code>session_fork</code> 创建独立的平行副本</li></ul></div><h2 id="常见问题排查" tabindex="-1">常见问题排查 <a class="header-anchor" href="#常见问题排查" aria-label="Permalink to &quot;常见问题排查&quot;">​</a></h2><h3 id="会话未找到" tabindex="-1">会话未找到 <a class="header-anchor" href="#会话未找到" aria-label="Permalink to &quot;会话未找到&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>session_info(session_id=&quot;abc123&quot;)</span></span>
<span class="line"><span># 返回: Session not found: abc123</span></span></code></pre></div><p>可能原因：</p><ul><li>会话 ID 拼写错误 — 用 <code>session_list</code> 确认有效的会话 ID</li><li>会话属于其他项目目录 — <code>session_list</code> 默认按当前项目过滤，指定 <code>project_path</code> 参数可跨项目搜索</li><li>会话已被清理或过期</li></ul><h3 id="导出路径权限被拒绝" tabindex="-1">导出路径权限被拒绝 <a class="header-anchor" href="#导出路径权限被拒绝" aria-label="Permalink to &quot;导出路径权限被拒绝&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>session_export(session_id=&quot;abc123&quot;, format=&quot;markdown&quot;, output_path=&quot;/root/exports/session.md&quot;)</span></span></code></pre></div><p>如果输出路径不可写，工具会静默回退到返回内联字符串。请在导出前确认目标目录存在且可写。建议使用项目内路径，如 <code>exports/session.md</code>。</p><h3 id="标签未显示" tabindex="-1">标签未显示 <a class="header-anchor" href="#标签未显示" aria-label="Permalink to &quot;标签未显示&quot;">​</a></h3><p>标签存储在 opencode 内建的会话 <code>metadata</code> 字段（键 <code>rolebox_tags</code>），仅当前会话的代理可以读写。如果标签未出现：</p><ul><li>确认使用 <code>list=true</code> 参数查询，而非仅依赖注入摘要</li><li>标签数据通过 <code>session_tag</code> 写入，不会自动传播到之前已结束的会话</li><li>重启会话后，新代理需要通过 <code>session_tag</code> 工具重新检索才可看到标签</li></ul><h3 id="时间线无数据" tabindex="-1">时间线无数据 <a class="header-anchor" href="#时间线无数据" aria-label="Permalink to &quot;时间线无数据&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>task_chronology()</span></span>
<span class="line"><span># 返回: No tasks found.</span></span></code></pre></div><p><code>task_chronology</code> 追踪的是 dispatch 调度任务。如果当前项目尚未进行任何调度（未使用 <code>dispatch</code> 工具），则时间线为空。请先执行至少一次 dispatch 调用。</p><blockquote><p><strong>免责声明</strong></p><p>本文档基于内部实现策略文档整理。具体行为可能因版本变化而不同，以实际源码为准。实现策略原文参见<a href="/rolebox-docs/04-Advanced/design-decisions/session-tools-strategy.html">会话工具实现策略文档</a>，仅供内部参考。</p></blockquote><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/rolebox-docs/04-Advanced/memory-system.html">记忆系统</a> — 跨会话持久记忆</li><li><a href="/rolebox-docs/03-Reference/cli.html">CLI 使用</a> — 命令行工具完整参考</li><li><a href="/rolebox-docs/03-Reference/dispatch-config.html">调度配置</a> — 并发与预算控制</li></ul>`,91)])])}const b=a(t,[["render",i]]);export{u as __pageData,b as default};
